# Data Initialization
async def create_db_and_tables():
    async with engine.begin() as conn:
        await conn.run_sync(Base.metadata.create_all)

    async with AsyncSessionLocal() as session:
        # Check if data already exists to prevent duplicates on restart
        if (await session.execute(sqlalchemy.select(Category))).scalars().first() is not None:
            return

        print("Initializing database with sample data...")

        category1 = Category(name="Electronics")
        category2 = Category(name="Books")

        seller1 = Seller(name="TechCo", contact_email="contact@techco.com")
        seller2 = Seller(name="BookWorm Inc.", contact_email="sales@bookworm.com")

        session.add_all([category1, category2, seller1, seller2])
        await session.commit()

        await session.refresh(category1)
        await session.refresh(category2)
        await session.refresh(seller1)
        await session.refresh(seller2)

        product1 = Product(name="Laptop Pro", description="Powerful laptop for professionals", price=1200.00, stock=50, category=category1, seller=seller1)
        product2 = Product(name="Wireless Headphones", description="Noise-cancelling, comfortable headphones", price=150.00, stock=200, category=category1, seller=seller1)
        product3 = Product(name="Python Programming Guide", description="Comprehensive guide for Python beginners", price=35.00, stock=100, category=category2, seller=seller2)
        product4 = Product(name="Advanced Algorithms", description="Deep dive into complex algorithms", price=60.00, stock=75, category=category2, seller=seller2)

        session.add_all([product1, product2, product3, product4])
        await session.commit()

        await session.refresh(product1)
        await session.refresh(product2)
        await session.refresh(product3)
        await session.refresh(product4)

        review1 = Review(product=product1, rating=5, comment="Excellent performance!", reviewer_name="Alice")
        review2 = Review(product=product1, rating=4, comment="Good laptop, but a bit heavy.", reviewer_name="Bob")
        review3 = Review(product=product2, rating=5, comment="Amazing sound quality!", reviewer_name="Charlie")
        review4 = Review(product=product3, rating=5, comment="Very clear explanations.", reviewer_name="David")

        image1 = ProductImage(product=product1, url="http://example.com/laptop1.jpg", alt_text="Laptop front view")
        image2 = ProductImage(product=product1, url="http://example.com/laptop2.jpg", alt_text="Laptop keyboard")
        image3 = ProductImage(product=product2, url="http://example.com/headphones1.jpg", alt_text="Headphones on stand")
        image4 = ProductImage(product=product3, url="http://example.com/python_book.jpg", alt_text="Python book cover")

        session.add_all([review1, review2, review3, review4, image1, image2, image3, image4])
        await session.commit()
        print("Database initialized.")

