@strawberry.type
class CategoryGQL:
    id: int
    name: str

    @strawberry.field
    async def products(self, info) -> List["ProductGQL"]:
        db_session = info.context["db_session"]
        stmt = sqlalchemy.select(Product).where(Product.category_id == self.id)
        result = await db_session.execute(stmt)
        return result.scalars().all()


