@strawberry.type
class ProductGQL:
    id: int
    name: str
    description: Optional[str]
    price: float
    stock: int

    @strawberry.field
    async def category(self, info) -> CategoryGQL:
        # Thanks to lazy="selectin" in relationships, this will often be pre-loaded.
        # But if not, Strawberry's resolvers will handle it.
        # This explicit fetch ensures it works even if relationships weren't eager.
        db_session = info.context["db_session"]
        stmt = sqlalchemy.select(Category).where(Category.id == self.category_id)
        result = await db_session.execute(stmt)
        return result.scalars().first()

    @strawberry.field
    async def seller(self, info) -> SellerGQL:
        db_session = info.context["db_session"]
        stmt = sqlalchemy.select(Seller).where(Seller.id == self.seller_id)
        result = await db_session.execute(stmt)
        return result.scalars().first()

    @strawberry.field
    async def reviews(self, info) -> List[ReviewGQL]:
        db_session = info.context["db_session"]
        stmt = sqlalchemy.select(Review).where(Review.product_id == self.id)
        result = await db_session.execute(stmt)
        return result.scalars().all()

